function calculateAndReturnTheLengthOfATriangleStrip(startTriangleIndex: number, startVertex: number): number {
  let count = 0;
  let m1 = verts[(startVertex + 2) % 3];
  let m2 = verts[(startVertex + 1) % 3];
  for (let j = startTriangleIndex + 1; j < numTris; j++) {
    for (let k = 0; k < 3; k++) {
      if (tris[j][k] === m1 && tris[j][(k+1)%3] === m2) {
        count++;
        if (count & 1) m2 = tris[j][(k+2)%3];
        else m1 = tris[j][(k+2)%3];
        break;
      }
    }
  }
  return count;
}
